SELECT
	member_chnl_id
FROM
	TB_MEMBER_CHNL

	AND character_no = #{characterNo}
	AND member_no = #{memberNo}

		AND member_chnl_id != #{excludeChannelId}


ORDER BY member_chnl_sn ASC

	LIMIT #{pageable.offset}, #{pageable.pageSize}

SELECT a.member_chnl_id AS memberChannelId, a.member_chnl_nm AS memberChannelName, a.member_chnl_sn AS channelPriority, a.pin_type AS pinType, a.pin_type_id AS pinTypeId, ( SELECT COUNT(*) FROM tb_map_member_chnl_track aa JOIN tb_track bb ON aa.track_id = bb.track_id AND bb.disp_status_yn= 'Y' AND now() BETWEEN bb.disp_start_dtime AND bb.disp_end_dtime WHERE aa.member_chnl_id = a.member_chnl_id
) AS trackCount, IFNULL(a.chnl_play_tm, 0) AS channelPlayTime, a.create_dtime AS createDateTime, a.update_dtime AS updateDateTime, b.album_id AS albumId, b.title AS albumTitle, c.album_img_size AS size, c.album_img_url AS url, c.update_dtime AS albumImgUpdateDateTime FROM tb_member_chnl a LEFT JOIN ted_album b ON b.album_id = ( SELECT aa.album_id FROM tb_track aa JOIN tb_map_member_chnl_track bb ON aa.track_id = bb.track_id JOIN tb_member_chnl cc ON bb.member_chnl_id = cc.member_chnl_id WHERE cc.member_chnl_id = a.member_chnl_id AND aa.disp_status_yn = 'Y' AND now() BETWEEN aa.disp_start_dtime AND aa.disp_end_dtime ORDER BY bb.update_dtime DESC, bb.track_sn ASC LIMIT 1 ) LEFT JOIN tb_album_img c ON b.album_id = c.album_id WHERE a.member_chnl_id IN
#{channelId}
ORDER BY a.member_chnl_sn ASC

SELECT
COUNT(member_chnl_id)
FROM
tb_member_chnl

	AND character_no = #{characterNo}
	AND member_no = #{memberNo}

SELECT
	COUNT(member_chnl_id)
FROM
	TB_MEMBER_CHNL

	AND character_no = #{characterNo}
	AND member_no = #{memberNo}

SELECT
	count(*)
FROM
	tb_member_chnl
WHERE character_no = #{characterNo}
AND member_no = #{memberNo}
AND member_chnl_nm = #{channelName}

SELECT
	member_chnl_nm
FROM
	tb_member_chnl
WHERE character_no = #{characterNo}
AND member_no = #{memberNo}
AND member_chnl_nm like #{channelName}

